# Precompile the regex used to strip injected memory blocks. The fast-path
# substring check avoids any regex work for the common case of no block.
_MEMORY_RE = re.compile(
    rf"{re.escape(MEMORY_OPEN)}[\s\S]*?{re.escape(MEMORY_CLOSE)}\s*",
    flags=re.IGNORECASE,
)

# Telemetry piggybacks on the host process's global TracerProvider /
# MeterProvider.  When Open WebUI has ENABLE_OTEL=true those providers
# are installed and the plugin's spans and metrics flow through the
# same pipeline.  When no provider is configured the OTel API returns
# no-op tracers and meters, so calls are safe regardless.
_tracer: trace.Tracer | None = None
_meter: metrics.Meter | None = None


def get_tracer() -> trace.Tracer:
    """Return the lazily initialized OpenTelemetry tracer for this plugin."""
    global _tracer
    if _tracer is None:
        _tracer = trace.get_tracer("openwebui_honcho")
    return _tracer


def get_meter() -> metrics.Meter:
    """Return the lazily initialized OpenTelemetry meter for this plugin."""
    global _meter
    if _meter is None:
        _meter = metrics.get_meter("openwebui_honcho")
        _init_metrics()
    return _meter


def set_span_status(span: trace.Span, exc: Exception | None = None) -> None:
    """Mark a span OK or ERROR and record exceptions."""
    if exc is None:
        span.set_status(Status(StatusCode.OK))
    else:
        span.set_status(Status(StatusCode.ERROR, description=str(exc)[:1000]))
        span.record_exception(exc)


def record_metric(
    instrument_name: str,
    value: int | float,
    attributes: dict[str, Any] | None = None,
) -> None:
    """Record a metric (no-op when no MeterProvider is configured)."""
    instrument = _metric_instruments.get(instrument_name)
    if instrument is None:
        return
    if hasattr(instrument, "add"):
        instrument.add(value, attributes)  # type: ignore[attr-defined]
    elif hasattr(instrument, "record"):
        instrument.record(value, attributes)  # type: ignore[attr-defined]


_metric_instruments: dict[str, Any] = {}


def _init_metrics() -> None:
    """Create metric instruments lazily (no-op when no MeterProvider is set)."""
    if _metric_instruments:
        return
    meter = get_meter()
    _metric_instruments["requests_total"] = meter.create_counter(
        "honcho.memory_requests_total",
        description="Total number of memory plugin requests",
    )
    _metric_instruments["messages_persisted_total"] = meter.create_counter(
        "honcho.memory_messages_persisted_total",
        description="Total number of chat messages persisted to Honcho",
    )
    _metric_instruments["operation_duration"] = meter.create_histogram(
        "honcho.memory_operation_duration_seconds",
        description="Duration of memory plugin operations",
    )


