    async def query_user_peer_card(
        self,
        user_id: str,
        *,
        query: str,
        top_k: int,
        max_distance: float = 0.8,
        include_most_frequent: bool = True,
    ) -> list[str]:
        """Search the user's self-card semantically using peer context.

        Falls back to substring matching if the context call returns nothing.
        """
        user_peer_id = derive_id("usr", user_id, self.config.identity_salt)
        start = _time.monotonic()
        with get_tracer().start_as_current_span("honcho.query_user_peer_card") as span:
            span.set_attribute("honcho.user_peer_id", user_peer_id)
            span.set_attribute("honcho.query_length", len(query))
            _success = True
            try:
                user_peer = await self._get_user_peer(user_id)
                if not query.strip():
                    card = await user_peer.aio.card()
                    result = (card or [])[:top_k]
                    set_span_status(span)
                    return result

                context = await user_peer.aio.context(
                    search_query=query,
                    search_top_k=top_k,
                    search_max_distance=max_distance,
                    include_most_frequent=include_most_frequent,
                )
                results: list[str] = []
                if context.representation:
                    results.append(context.representation)
                elif context.peer_card:
                    results.extend(context.peer_card)
                if not results:
                    # Fallback to substring matching over the full self-card.
                    card = await user_peer.aio.card() or []
                    query_lower = query.lower()
                    results = [f for f in card if query_lower in f.lower()][:top_k]
                span.set_attribute("honcho.result_count", len(results))
                set_span_status(span)
                return results[:top_k]
            except Exception as exc:
                _success = False
                set_span_status(span, exc)
                raise
            finally:
                record_metric(
                    "operation_duration",
                    _time.monotonic() - start,
                    self._telemetry_attributes("query_user_peer_card"),
                )
                record_metric(
                    "requests_total",
                    1,
                    {
                        **self._telemetry_attributes("query_user_peer_card"),
                        "result": "success" if _success else "error",
                    },
                )

    async def edit_user_peer_card(
        self,
        user_id: str,
        editor: Callable[[list[str]], list[str]],
    ) -> list[str]:
        """Edit the user peer self-card atomically per user.

        The editor callable receives the current card list and returns the new
        list. Concurrent edits for the same user are serialized.
        """
        cls = self.__class__
        user_peer_id = derive_id("usr", user_id, self.config.identity_salt)
        async with cls._card_locks_lock:
            lock = cls._card_locks.get(user_peer_id)
            if lock is None:
                lock = asyncio.Lock()
                cls._card_locks[user_peer_id] = lock
            while len(cls._card_locks) > 2048:
                del cls._card_locks[next(iter(cls._card_locks))]
        start = _time.monotonic()
        with get_tracer().start_as_current_span("honcho.edit_user_peer_card") as span:
            span.set_attribute("honcho.user_peer_id", user_peer_id)
            _success = True
            try:
                async with lock:
                    user_peer = await self._get_user_peer(user_id)
                    current = await user_peer.aio.card() or []
                    span.set_attribute("honcho.card_size_before", len(current))
                    updated = editor(current)
                    span.set_attribute("honcho.card_size_after", len(updated))
                    result = await user_peer.aio.set_card(updated) or []
                    set_span_status(span)
                    return result
            except Exception as exc:
                _success = False
                set_span_status(span, exc)
                raise
            finally:
                record_metric(
                    "operation_duration",
                    _time.monotonic() - start,
                    self._telemetry_attributes("edit_user_peer_card"),
                )
                record_metric(
                    "requests_total",
                    1,
                    {
                        **self._telemetry_attributes("edit_user_peer_card"),
                        "result": "success" if _success else "error",
                    },
                )

    async def resources(
        self, user_id: str, model_id: str, chat_id: str
    ) -> tuple[Any, Any, Any, Identity]:
        """Resolve and cache the strictly scoped peers and session."""
        cache_key = (
            self.config.workspace_id,
            self.config.identity_salt,
            user_id,
            model_id,
            chat_id,
        )
        cached = self.__class__._resources.get(cache_key)
        if cached:
            self.__class__._resources.move_to_end(cache_key)
            LOG.debug("Honcho resources cache hit: session_id=%s", cache_key[4][:17])
            return cached
        async with self._resource_lock:
            cached = self.__class__._resources.get(cache_key)
            if cached:
                self.__class__._resources.move_to_end(cache_key)
                LOG.debug(
                    "Honcho resources cache hit (under lock): session_id=%s", cache_key[4][:17]
                )
                return cached
            LOG.debug("Honcho resources cache miss: creating peers and session")
            resources = await self._create_resources(user_id, model_id, chat_id)
            self.__class__._resources[cache_key] = resources
            self.__class__._resources.move_to_end(cache_key)
            while len(self.__class__._resources) > self._resource_cache_limit:
                self.__class__._resources.popitem(last=False)
            return resources

    async def _create_resources(
        self, user_id: str, model_id: str, chat_id: str
    ) -> tuple[Any, Any, Any, Identity]:
        identity = derive_identity(user_id, model_id, chat_id, self.config.identity_salt)
        start = _time.monotonic()
        with get_tracer().start_as_current_span("honcho.create_resources") as span:
            span.set_attribute("honcho.user_peer_id", identity.user_peer_id)
            span.set_attribute("honcho.assistant_peer_id", identity.assistant_peer_id)
            span.set_attribute("honcho.session_id", identity.session_id)
            _success = True
            try:
                honcho = await self.client()
                user_peer = await honcho.aio.peer(
                    identity.user_peer_id,
                    configuration=PeerConfig(observe_me=True),
                )
                assistant_peer = await honcho.aio.peer(
                    identity.assistant_peer_id,
                    configuration=PeerConfig(observe_me=False),
                )
                session = await honcho.aio.session(
                    identity.session_id,
                    metadata={"source": "openwebui", "schema_version": SCHEMA_VERSION},
                    peers=[
                        (
                            user_peer,
                            SessionPeerConfig(observe_me=True, observe_others=False),
                        ),
                        (
                            assistant_peer,
                            SessionPeerConfig(observe_me=False, observe_others=True),
                        ),
                    ],
                )
                set_span_status(span)
                return user_peer, assistant_peer, session, identity
            except Exception as exc:
                _success = False
                set_span_status(span, exc)
                raise
            finally:
                record_metric(
                    "operation_duration",
                    _time.monotonic() - start,
                    self._telemetry_attributes("create_resources"),
                )
                record_metric(
                    "requests_total",
                    1,
                    {
                        **self._telemetry_attributes("create_resources"),
                        "result": "success" if _success else "error",
                    },
                )

