    async def add_completed_messages(
        self,
        user_id: str,
        model_id: str,
        chat_id: str,
        messages: list[dict[str, Any]],
    ) -> int:
        """Persist unseen completed messages after stripping injected context.

        Deduplication is best-effort: we query for an existing message with the
        same event_id before inserting, but this is a read-then-write pattern
        protected only by an in-process asyncio.Lock.  In multi-worker or
        multi-replica Open WebUI deployments two workers may both see no existing
        message and both insert, producing a duplicate.  Honcho's dreaming agent
        handles duplicate content gracefully at the representation level, and
        the event_id in message metadata allows post-hoc identification of
        duplicates if cleanup is ever needed.  True cross-worker atomicity would
        require an idempotency key or server-side unique constraint not available
        in the Honcho v2.1.2 API.
        """
        session_key = (user_id, chat_id)
        cls = self.__class__
        async with cls._capture_locks_lock:
            lock = cls._capture_locks.get(session_key)
            if lock is None:
                lock = asyncio.Lock()
                cls._capture_locks[session_key] = lock
            # Evict oldest entries if the dict is over capacity; never clear
            # the whole dict because concurrent captures may be holding locks.
            while len(cls._capture_locks) > 2048:
                del cls._capture_locks[next(iter(cls._capture_locks))]
        start = _time.monotonic()
        async with lock:
            with get_tracer().start_as_current_span("honcho.add_completed_messages") as span:
                span.set_attribute("honcho.candidate_count", len(messages))
                _success = True
                try:
                    user_peer, assistant_peer, session, _ = await self.resources(
                        user_id, model_id, chat_id
                    )
                    pending = []
                    for message in messages:
                        message_id = str(message.get("id") or "")
                        content = strip_memory_context(extract_text(message.get("content")))
                        if not message_id or not content:
                            LOG.debug(
                                "Honcho outlet skipped message (no id or empty content): role=%s",
                                message.get("role"),
                            )
                            continue
                        event_id = derive_event_id(
                            user_id, chat_id, message_id, self.config.identity_salt
                        )
                        page = await session.aio.messages(
                            filters={"metadata": {"event_id": event_id}}, size=1
                        )
                        if page.items:
                            LOG.debug("Honcho outlet dedup hit: event_id=%s", event_id[:17])
                            continue
                        peer = user_peer if message.get("role") == "user" else assistant_peer
                        created_at = _normalize_timestamp(message.get("timestamp"))
                        pending.append(
                            peer.message(
                                content,
                                metadata={
                                    "event_id": event_id,
                                    "role": message.get("role"),
                                    "source": "openwebui",
                                    "schema_version": SCHEMA_VERSION,
                                },
                                created_at=created_at,
                            )
                        )
                    if pending:
                        await session.aio.add_messages(pending)
                    span.set_attribute("honcho.persisted_count", len(pending))
                    set_span_status(span)
                    record_metric("messages_persisted_total", len(pending))
                    return len(pending)
                except Exception as exc:
                    _success = False
                    set_span_status(span, exc)
                    raise
                finally:
                    record_metric(
                        "operation_duration",
                        _time.monotonic() - start,
                        self._telemetry_attributes("add_completed_messages"),
                    )
                    record_metric(
                        "requests_total",
                        1,
                        {
                            **self._telemetry_attributes("add_completed_messages"),
                            "result": "success" if _success else "error",
                        },
                    )

